/** UsptTaskPartcptsHistDao.insert */
insert into uspt_task_partcpts_hist (
				 task_partcpts_hist_id
				,cnvn_change_req_id
				,confm_task_partcpts_hist_id
				,partcpts_nm
				,chrg_realm_nm
				,enc_mbtlnum
				,enc_brthdy
				,partcptn_rate
				,member_id
				,creator_id
				,created_dt
			) values (
				 #{taskPartcptsHistId}
				,#{cnvnChangeReqId}
				,#{confmTaskPartcptsHistId}
				,#{partcptsNm}
				,#{chrgRealmNm}
				,#{encMbtlnum}
				,#{encBrthdy}
				,#{partcptnRate}
				,#{memberId}
				,#{creatorId}
				,#{createdDt}
			)
